import React from 'react';
import './App.css';

function App() {
  return (
    <div className="portfolio-container">
      {/* नेविगेशन बार */}
      <nav className="navbar">
        <div className="logo">Freelance<span>Dev</span></div>
        <ul className="nav-links">
          <li><a href="#home">Home</a></li>
          <li><a href="#about">About</a></li>
          <li><a href="#skills">Skills</a></li>
          <li><a href="#contact">Contact</a></li>
        </ul>
      </nav>

      {/* हीरो सेक्शन */}
      <header className="hero-section">
        <div className="hero-content">
          <h1>नमस्कार, मी <span>[तुमचे नाव]</span></h1>
          <p className="typewriter">एक प्रोफेशनल स्टुडंट फ्रीलान्सर आणि वेब डेव्हलपर</p>
          <div className="cta-container">
            <a href="#contact" className="btn-primary">मला कामासाठी संपर्क करा</a>
          </div>
        </div>
      </header>

      {/* बैकग्राउंड एनिमेटेड सर्कल्स (Modern Look के लिए) */}
      <div className="circle circle-1"></div>
      <div className="circle circle-2"></div>
    </div>
  );
}

export default App;
